const html = $input.item.json.data;
const annonces = [];

const blocs = html.split(/data-annonce="/).slice(1);

for (const bloc of blocs) {
  try {
    const jsonStringRaw = bloc.substring(0, bloc.indexOf('"'));
    const jsonString = jsonStringRaw.replace(/&quot;/g, '"');

    let dataAnnonce = {};
    try { dataAnnonce = JSON.parse(jsonString); } catch(e) {}

    const titreMatch = bloc.match(/class="h1"[^>]*>\s*([^<]+)\s*<\/span>/);
    const titre = titreMatch ? titreMatch[1].trim() : '';

    const prixMatch = bloc.match(/class="item-price[^"]*">\s*([\d\s\.]+)(?:&nbsp;)?&euro;/);
    const prix = prixMatch ? parseInt(prixMatch[1].replace(/[^\d]/g, ''), 10) : (dataAnnonce.prix || null);

    const urlMatch = bloc.match(/href="(\/annonces\/[^"]+)"/);
    const url = urlMatch ? 'https://www.pap.fr' + urlMatch[1] : '';

    const descMatch = bloc.match(/class="item-description"[^>]*>\s*([\s\S]*?)\s*<\/p>/);
    const description = descMatch ? descMatch[1].replace(/<[^>]+>/g, '').trim() : '';

    const tags = [...bloc.matchAll(/<li[^>]*>(.*?)<\/li>/g)].map(m => m[1].replace(/<[^>]+>/g, '').trim().toLowerCase());

    let surface = dataAnnonce.surface || null;
    let pieces = null;
    let chambres = null;

    tags.forEach(tag => {
      if (tag.includes('m²') || tag.includes('m2')) {
        const s = tag.match(/(\d+)/);
        if (s) surface = parseInt(s[1], 10);
      }
      if (tag.includes('pièce') || tag.includes('piece')) {
        const p = tag.match(/(\d+)/);
        if (p) pieces = parseInt(p[1], 10);
      }
      if (tag.includes('chambre')) {
        const c = tag.match(/(\d+)/);
        if (c) chambres = parseInt(c[1], 10);
      }
    });

    let dpe = null;
    const dpeMatch = bloc.match(/dpe[-_ ]?([a-gA-G])\b/i);
    if (dpeMatch) dpe = dpeMatch[1].toUpperCase();

    if (dataAnnonce.id || titre) {
      annonces.push({
        json: {
          id: dataAnnonce.id || null,
          prix,
          localisation: titre,
          url,
          surface_m2: surface,
          nb_pieces: pieces,
          nb_chambres: chambres,
          dpe,
          description,
          tags_bruts: tags,
          source: 'PAP',
          date_scraping: new Date().toISOString()
        }
      });
    }
  } catch(error) {
    continue;
  }
}

return annonces;

const claudeItem = $input.first().json;
// Les données originales viennent de Mise en forme pour IA (passées en avant)
const original = $('Mise en forme pour IA').first().json;

const formatFrDate = (dateStr) => {
  if (!dateStr) return 'Date inconnue';
  try {
    return new Intl.DateTimeFormat('fr-FR', {
      day: '2-digit', month: '2-digit', year: 'numeric',
      hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Paris'
    }).format(new Date(dateStr)).replace(',', ' -');
  } catch (e) { return dateStr; }
};

const rawContent = claudeItem.content?.[0]?.text || '';

let parsed = { score: 0, analyse: 'Erreur parsing', script: '', accroche: '', potentiel: 'Inconnu', type: '', etage: 'Non précisé' };

try {
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) parsed = JSON.parse(jsonMatch[0]);
} catch(e) {
  console.error('Erreur parsing JSON Claude : ' + e.message);
}

return [{
  json: {
    ...original,
    date:     formatFrDate(original.date_scraping),
    score:    parsed.score    || 0,
    analyse:  parsed.analyse  || '',
    script:   parsed.script   || '',
    accroche: parsed.accroche || '',
    potentiel:parsed.potentiel|| 'Non détecté',
    type:     parsed.type     || '',
    emoji:    (parsed.type || '').toLowerCase().includes('maison') ? '🏠' : '🏢',
    etage:    parsed.etage    || 'Non précisé'
  }
}];

// Déclenché par la sortie 'done' de Split In Batches
// Reçoit les items originaux scrapés (sans analyse IA — celle-ci est dans LeadFlow)
const items = $input.all();
const cfg = $('⚙️ Configuration').first().json;

const lignes = items.map(a => {
  const d = a.json;
  const localisation = d.localisation || 'Localisation non précisée';
  const prix = d.prix ? Number(d.prix).toLocaleString('fr-FR') + ' €' : 'Prix N/A';
  const url = d.url || '';
  const source = d.source || 'PAP';

  return [
    '<div style="background:white;border:1px solid #e0e0e0;margin:10px 0;border-radius:6px;padding:14px;">',
    '<b style="color:#1B3A6B;font-size:14px;">' + localisation + '</b>',
    '<div style="margin-top:6px;color:#555;font-size:13px;">💰 <b>' + prix + '</b> &nbsp;·&nbsp; 📍 ' + source + '</div>',
    url ? '<a href="' + url + '" style="display:inline-block;margin-top:10px;background:#2E5FAC;color:white;padding:6px 14px;border-radius:4px;text-decoration:none;font-size:12px;font-weight:bold;">Voir l\'annonce →</a>' : '',
    '</div>'
  ].join('');
}).join('');

const html = [
  '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f6fa;">',
  '<div style="background:#1B3A6B;padding:24px;border-radius:8px 8px 0 0;">',
  '<h2 style="color:white;margin:0;font-size:20px;">📋 Pige du ' + new Date().toLocaleDateString('fr-FR') + '</h2>',
  '<p style="color:#a8c4e8;margin:8px 0 0;font-size:13px;">' + items.length + ' nouvelles annonces analysées par IA et ajoutées à LeadFlow</p>',
  '</div>',
  '<div style="padding:0 16px 16px;">' + lignes + '</div>',
  '<div style="background:#1B3A6B;padding:16px;border-radius:0 0 8px 8px;text-align:center;">',
  '<a href="' + cfg.LEADFLOW_URL + '/pige" style="color:white;font-size:13px;text-decoration:none;">Consulter l\'analyse IA complète dans LeadFlow →</a>',
  '</div>',
  '</div>'
].join('');

return [{ json: {
  html,
  subject: '📋 Pige du ' + new Date().toLocaleDateString('fr-FR') + ' — ' + items.length + ' nouvelles annonces'
} }];
